<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';use App\Support\SpanishDateFormatter;date_default_timezone_set('America/Mexico_City');
test('fecha con microsegundos',fn()=>same(SpanishDateFormatter::format('2026-07-22 01:57:39.818012'),'22 jul 2026, 1:57 a. m.'));test('fecha sin microsegundos',fn()=>same(SpanishDateFormatter::format('2026-07-22 13:57:39'),'22 jul 2026, 1:57 p. m.'));test('null',fn()=>same(SpanishDateFormatter::format(null),'—'));test('vacía',fn()=>same(SpanishDateFormatter::format(''),'—'));test('inválida',fn()=>same(SpanishDateFormatter::format('fecha imposible'),'—'));test('medianoche',fn()=>same(SpanishDateFormatter::format('2026-07-22 00:00:00'),'22 jul 2026, 12:00 a. m.'));test('mediodía',fn()=>same(SpanishDateFormatter::format('2026-07-22 12:00:00'),'22 jul 2026, 12:00 p. m.'));test('zona horaria configurada',fn()=>same(date_default_timezone_get(),'America/Mexico_City'));finish('Date Formatter');
